    for (const originalKey in item.binary) {
      if (Object.prototype.hasOwnProperty.call(item.binary, originalKey)) {
        // --- 修改点：根据原始 Key 的前缀判断并重命名 ---
        let newKey;
        if (originalKey.startsWith('cpimage')) {
          newKey = `cpimage_${++cpimageCount}`;
        } else if (originalKey.startsWith('ckimage')) {
          newKey = `ckimage_${++ckimageCount}`;
        } else {
          // 如果不匹配，保持原样或者跳过（这里保持原样）
          newKey = originalKey;
        }

        images[newKey] = {
          ...item.binary[originalKey],
          sourceNode: 'current_input',
          sourceField: originalKey,
          originalIndex: i
